mapper.update:
UPDATE chat_session
SET last_message = #{lastMessage}, last_time = NOW()
WHERE id = #{id}

UPDATE chat_session
SET user1_unread = user1_unread + 1
WHERE id = #{id} AND #{isUser1} = true;
UPDATE chat_session
SET user2_unread = user2_unread + 1
WHERE id = #{id} AND #{isUser1} = false;

UPDATE chat_session
SET user1_unread = 0
WHERE id = #{id} AND #{isUser1} = true;
UPDATE chat_session
SET user2_unread = 0
WHERE id = #{id} AND #{isUser1} = false;

mapper.select:
SELECT * FROM chat_session
WHERE user1_id = #{userId} OR user2_id = #{userId}
ORDER BY last_time DESC
LIMIT #{offset}, #{limit}
